 namespace League\CommonMark\Extension\InlinesOnly; use League\CommonMark\Block\Element\AbstractBlock; use League\CommonMark\Block\Element\Document; use League\CommonMark\Block\Element\InlineContainerInterface; use League\CommonMark\Block\Renderer\BlockRendererInterface; use League\CommonMark\ElementRendererInterface; use League\CommonMark\Inline\Element\AbstractInline; final class ChildRenderer implements BlockRendererInterface { public function render(AbstractBlock $block, ElementRendererInterface $htmlRenderer, bool $inTightList = false) { $out = ''; if ($block instanceof InlineContainerInterface) { $children = $block->children(); $out .= $htmlRenderer->renderInlines($children); } else { $children = $block->children(); $out .= $htmlRenderer->renderBlocks($children); } if (!($block instanceof Document)) { $out .= "\n"; } return $out; } } 